package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    void testGetNullString_DefaultNull() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        assertNull(format.getNullString());
    }

    @Test
    void testGetNullString_WithNullString() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT.withNullString("NULL");
        assertEquals("NULL", format.getNullString());
    }

    @Test
    void testGetNullString_ReflectionSetNullString() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;

        java.lang.reflect.Field nullStringField = CSVFormat.class.getDeclaredField("nullString");
        nullStringField.setAccessible(true);

        // Remove final modifier via reflection
        java.lang.reflect.Field modifiersField = java.lang.reflect.Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(nullStringField, nullStringField.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

        nullStringField.set(format, "REF_NULL");

        assertEquals("REF_NULL", format.getNullString());
    }
}
